def transform(table):
    if not table:
        return []

    # Identify the first column as the identifier and subsequent columns as value columns.
    # The structure is: [Header Row, Empty Row, Data Row 1, Data Row 2, ...]
    # We need to group by the first column (District name) and transpose the years.

    # Find the header row (first row with non-empty first column)
    header_row_idx = 0
    while header_row_idx < len(table) and (not table[header_row_idx][0] or table[header_row_idx][0] == ""):
        header_row_idx += 1

    if header_row_idx >= len(table):
        return []

    header = table[header_row_idx]

    # Let's collect all data rows and group by district name
    districts = {}

    for i in range(header_row_idx + 1, len(table)):
        row = table[i]
        if len(row) < 2:
            continue
        district_name = row[0]
        if not district_name or district_name == "":
            continue

        if district_name not in districts:
            districts[district_name] = {}

        # Check if this is a year row (second column is a year)
        if len(row) >= 2 and row[1] and row[1].isdigit():
            year = row[1]
            value = row[2] if len(row) > 2 else ""
            districts[district_name][year] = value

    # Determine the years present
    all_years = set()
    for d in districts.values():
        all_years.update(d.keys())
    all_years = sorted(list(all_years))

    # Construct the output table
    # First row: empty string, then years
    result = [[""] + all_years]

    # Subsequent rows: district name, then values for each year
    for district_name in sorted(districts.keys()):
        row = [district_name]
        for year in all_years:
            row.append(districts[district_name].get(year, ""))
        result.append(row)

    return result

